// Error types
pyo3::create_exception!(_internal_bindings, LiterLlmError, pyo3::exceptions::PyException);
pyo3::create_exception!(_internal_bindings, AuthenticationError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, RateLimitedError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, BadRequestError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, ContextWindowExceededError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, ContentPolicyError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, NotFoundError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, ServerError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, ServiceUnavailableError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, LiterLlmTimeoutError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, StreamingError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, EndpointNotSupportedError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, InvalidHeaderError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, SerializationError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, BudgetExceededError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, HookRejectedError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, InternalError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, OutboundForbiddenError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, IdempotencyConflictError, LiterLlmError);
pyo3::create_exception!(_internal_bindings, IdempotencyInFlightError, LiterLlmError);

/// Convert a `liter_llm::LiterLlmError` error to a Python exception.
fn liter_llm_error_to_py_err(e: liter_llm::LiterLlmError) -> pyo3::PyErr {
    let msg = e.to_string();
    let args = (
        msg.clone(),
        e.status_code(),
        e.is_transient(),
        e.error_type().to_string(),
    );
    #[allow(unreachable_patterns)]
    match &e {
        liter_llm::LiterLlmError::Authentication { .. } => AuthenticationError::new_err(args),
        liter_llm::LiterLlmError::RateLimited { .. } => RateLimitedError::new_err(args),
        liter_llm::LiterLlmError::BadRequest { .. } => BadRequestError::new_err(args),
        liter_llm::LiterLlmError::ContextWindowExceeded { .. } => ContextWindowExceededError::new_err(args),
        liter_llm::LiterLlmError::ContentPolicy { .. } => ContentPolicyError::new_err(args),
        liter_llm::LiterLlmError::NotFound { .. } => NotFoundError::new_err(args),
        liter_llm::LiterLlmError::ServerError { .. } => ServerError::new_err(args),
        liter_llm::LiterLlmError::ServiceUnavailable { .. } => ServiceUnavailableError::new_err(args),
        liter_llm::LiterLlmError::Timeout => LiterLlmTimeoutError::new_err(args),
        liter_llm::LiterLlmError::Streaming { .. } => StreamingError::new_err(args),
        liter_llm::LiterLlmError::EndpointNotSupported { .. } => EndpointNotSupportedError::new_err(args),
        liter_llm::LiterLlmError::InvalidHeader { .. } => InvalidHeaderError::new_err(args),
        liter_llm::LiterLlmError::Serialization(..) => SerializationError::new_err(args),
        liter_llm::LiterLlmError::BudgetExceeded { .. } => BudgetExceededError::new_err(args),
        liter_llm::LiterLlmError::HookRejected { .. } => HookRejectedError::new_err(args),
        liter_llm::LiterLlmError::InternalError { .. } => InternalError::new_err(args),
        liter_llm::LiterLlmError::OutboundForbidden { .. } => OutboundForbiddenError::new_err(args),
        liter_llm::LiterLlmError::IdempotencyConflict { .. } => IdempotencyConflictError::new_err(args),
        liter_llm::LiterLlmError::IdempotencyInFlight { .. } => IdempotencyInFlightError::new_err(args),
        _ => LiterLlmError::new_err(args),
    }
}

#[pyclass(name = "LiterLlmErrorInfo")]
pub struct LiterLlmErrorInfo {
    pub status_code: u16,
    pub is_transient: bool,
    pub error_type: String,
}

#[pymethods]
impl LiterLlmErrorInfo {
    /// HTTP status code for this error (0 means no associated status).
    #[getter]
    fn status_code(&self) -> u16 {
        self.status_code
    }

    /// Returns `true` if the error is transient and a retry may succeed.
    #[getter]
    fn is_transient(&self) -> bool {
        self.is_transient
    }

    /// Machine-readable error category string for matching and logging.
    #[getter]
    fn error_type(&self) -> String {
        self.error_type.clone()
    }
}

/// Build a `LiterLlmErrorInfo` from any exception raised by the `LiterLlmError` hierarchy.
///
/// The converter stores `(message, status_code, is_transient, error_type)` in the
/// exception args tuple; this function extracts those values at indices 1–3.
#[pyfunction]
pub fn liter_llm_error_info(err: pyo3::Bound<'_, pyo3::types::PyAny>) -> LiterLlmErrorInfo {
    let args = err.getattr("args").ok();
    LiterLlmErrorInfo {
        status_code: args
            .as_ref()
            .and_then(|a| a.get_item(1).ok())
            .and_then(|v| v.extract::<u16>().ok())
            .unwrap_or(0),
        is_transient: args
            .as_ref()
            .and_then(|a| a.get_item(2).ok())
            .and_then(|v| v.extract::<bool>().ok())
            .unwrap_or(false),
        error_type: args
            .as_ref()
            .and_then(|a| a.get_item(3).ok())
            .and_then(|v| v.extract::<String>().ok())
            .unwrap_or_default(),
    }
}

